import 'package:flutter/material.dart'; import 'package:flutter_riverpod/flutter_riverpod.dart'; import '../../../../core/widgets/app_empty_view.dart'; import '../../../../core/widgets/app_loading_view.dart'; import '../providers/notification_controller.dart'; import '../providers/notification_providers.dart'; import '../widgets/notification_tile.dart';
class NotificationPage extends ConsumerWidget{const NotificationPage({super.key}); @override Widget build(BuildContext context,WidgetRef ref){final async=ref.watch(myNotificationsProvider); return Scaffold(appBar:AppBar(title:const Text('Notifications'),actions:[IconButton(onPressed:()=>ref.read(notificationControllerProvider.notifier).markAllAsRead(),icon:const Icon(Icons.done_all))]),body:async.when(loading:()=>const AppLoadingView(),error:(e,_)=>AppEmptyView(title:'Error',message:e.toString()),data:(items)=>items.isEmpty?const AppEmptyView(title:'Notification မရှိသေးပါ'):ListView.builder(itemCount:items.length,itemBuilder:(_,i)=>NotificationTile(notification:items[i],onTap:()=>ref.read(notificationControllerProvider.notifier).markAsRead(items[i].id)))));}}
